INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Quando me deparo com uma oportunidade que parece alinhada aos meus valores, mas exige um grande esforço inicial, eu geralmente:', 'behavior_choice', '{orientacao_sentido,evitacao,conflito_interno}', 2, 21, '{"Mergulho de cabeça, mesmo que seja difícil.","Analiso por um tempo, pondero os prós e contras e depois decido.","Começo com entusiasmo, mas perco o gás se o resultado não é imediato.","Evito o esforço e procuro algo mais fácil ou familiar."}', '{100,75,25,0}');
INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Eu me sinto em paz com as escolhas que fiz em relação ao meu propósito de vida até agora.', 'likert', '{nivel_satisfacao,orientacao_sentido}', 1.5, 22, '{"Discordo Totalmente","Discordo","Neutro","Concordo","Concordo Totalmente"}', '{0,25,50,75,100}');
