INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Com que frequência você se compara com outras pessoas e se sente inferior ou inadequado(a)?', 'frequency', '{alinhamento_identidade,nivel_satisfacao}', 1.2, 25, '{"Nunca","Raramente","Às vezes","Frequentemente","Sempre"}', '{0,25,50,75,100}');
INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Quando alguém próximo questiona minhas escolhas de vida, eu:', 'behavior_choice', '{pressao_externa,alinhamento_identidade,autoexpressao}', 2, 26, '{"Reavalio minhas escolhas e considero a opinião, mas sigo meu caminho se fizer sentido para mim.","Fico na defensiva e me justifico, mesmo que por dentro eu tenha dúvidas.","Sinto que talvez eles estejam certos e mudo de direção.","Ignoro a opinião e sigo em frente sem refletir."}', '{100,50,25,0}');
INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Eu tenho uma visão clara do tipo de vida que quero construir nos próximos 3 a 5 anos.', 'likert', '{orientacao_sentido,conflito_interno}', 1.5, 27, '{"Discordo Totalmente","Discordo","Neutro","Concordo","Concordo Totalmente"}', '{0,25,50,75,100}');
INSERT INTO questions (test_id, text, type, axes, weight, sort_order, options, option_scores) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', 'Eu sinto um vazio persistente, como se algo fundamental estivesse faltando na minha vida, mesmo quando as coisas parecem bem externamente.', 'likert', '{nivel_satisfacao,engajamento_emocional}', 2, 28, '{"Discordo Totalmente","Discordo","Neutro","Concordo","Concordo Totalmente"}', '{0,25,50,75,100}');
INSERT INTO report_templates (test_id, sections, output_rules) VALUES ('12fa74a9-53e0-4afd-abd8-1c31a57ead37', '[{"key": "titulo_combinado", "label": "Título Combinado do Diagnóstico", "description": "Uma frase curta e impactante que encapsula o diagnóstico central do usuário, baseada nos eixos dominantes de desconexão ou alinhamento.", "format": "text"}, {"key": "resumo_estado", "label": "Resumo do Estado Atual", "description": "Descrição narrativa de 3-5 sentenças do estado emocional e comportamental dominante do usuário em relação ao seu propósito e sentido de vida, baseada nos scores dos 8 eixos.", "format": "text"}, {"key": "diagnostico_critico", "label": "Diagnóstico Crítico", "description": "Identificação do ciclo predominante de desconexão: causa raiz, mecanismo de manutenção (como o ciclo se perpetua) e ponto de bloqueio principal.", "format": "text"}, {"key": "dor_central", "label": "Dor Central", "description": "A ferida emocional ou medo fundamental que sustenta os padrões de desconexão e falta de propósito, conectada diretamente aos eixos de menor score.", "format": "text"}, {"key": "gatilhos", "label": "Gatilhos Situacionais", "description": "Lista de 3-5 situações concretas e específicas que ativam a desconexão, a falta de direção ou o desalinhamento de vida.", "format": "list"}, {"key": "contradicoes", "label": "Contradições Internas", "description": "Análise dos conflitos entre intenção e ação, revelados pelo cruzamento de eixos opostos (ex: alta orientação de sentido com alta evitação).", "format": "text"}, {"key": "armadilhas_mentais", "label": "Armadilhas Mentais", "description": "Padrões de pensamento recorrentes que mantêm o usuário preso no ciclo de desconexão, como racionalizações, justificativas e crenças limitantes.", "format": "list"}, {"key": "direcao_desbloqueio", "label": "Direção de Desbloqueio", "description": "Plano de ação prático com: 1 ação concreta para os próximos 7 dias, área-chave de destravamento e micro-compromissos diários.", "format": "text"}, {"key": "o_que_nao_fazer", "label": "O Que NÃO Fazer", "description": "Lista de comportamentos e abordagens que o usuário deve evitar para não sabotar seu processo de reconexão com o propósito.", "format": "list"}, {"key": "perfil_comportamental", "label": "Perfil Comportamental", "description": "Nome criativo do perfil, estado mental dominante, traços comportamentais observáveis e nível de risco de manutenção do estado atual.", "format": "text"}]'::jsonb, '[]'::jsonb) ON CONFLICT (test_id) DO UPDATE SET sections = EXCLUDED.sections, output_rules = EXCLUDED.output_rules, updated_at = now();